package main

import (
	"context"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/auth"
	"go.flipt.io/flipt/internal/storage/auth/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// TestRegression_CookieBasedTokenExtraction tests that the authentication middleware
// does not extract client tokens from HTTP cookies.
//
// Issue: Browser-based sessions store authentication tokens in HTTP cookies
// (under the key `flipt_client_token`), but the authentication middleware only
// accepts tokens via the `Authorization` header using Bearer format.
func TestRegression_CookieBasedTokenExtraction(t *testing.T) {
	authenticator := memory.NewStore()

	// Create a valid client token
	clientToken, storedAuth, err := authenticator.CreateAuthentication(
		context.TODO(),
		&auth.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)
	require.NotNil(t, storedAuth)
	require.NotEmpty(t, clientToken)

	logger := zaptest.NewLogger(t)
	interceptor := auth.UnaryInterceptor(logger, authenticator)

	tests := []struct {
		name        string
		setupMD     func() metadata.MD
		expectError bool
		description string
	}{
		{
			name: "valid token in Authorization header (baseline - should succeed)",
			setupMD: func() metadata.MD {
				return metadata.MD{
					"Authorization": []string{"Bearer " + clientToken},
				}
			},
			expectError: false,
			description: "Bearer token authentication works as expected",
		},
		{
			name: "token in flipt_client_token cookie (issue - should fail)",
			setupMD: func() metadata.MD {
				// This simulates how cookies are passed in gRPC metadata
				// When HTTP cookies are sent in gRPC, they appear as metadata headers
				return metadata.MD{
					"flipt_client_token": []string{clientToken},
				}
			},
			expectError: true,
			description: "Cookie-based token is NOT extracted - this is the bug",
		},
		{
			name: "token in cookie header with name cookie (issue - should fail)",
			setupMD: func() metadata.MD {
				// Another way cookies might appear in metadata
				return metadata.MD{
					"cookie": []string{"flipt_client_token=" + clientToken},
				}
			},
			expectError: true,
			description: "Cookie in standard cookie header is NOT extracted",
		},
		{
			name: "token in x-flipt-token custom header (issue - should fail)",
			setupMD: func() metadata.MD {
				// A custom header that's not Authorization
				return metadata.MD{
					"x-flipt-token": []string{"Bearer " + clientToken},
				}
			},
			expectError: true,
			description: "Custom token headers are NOT checked",
		},
		{
			name: "no authentication headers (baseline - should fail)",
			setupMD: func() metadata.MD {
				return metadata.MD{}
			},
			expectError: true,
			description: "No auth headers results in failure",
		},
	}

	for _, test := range tests {
		test := test
		t.Run(test.name, func(t *testing.T) {
			ctx := metadata.NewIncomingContext(context.Background(), test.setupMD())

			var retrievedAuth *authrpc.Authentication
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				retrievedAuth = auth.GetAuthenticationFrom(ctx)
				return nil, nil
			}

			_, err := interceptor(ctx, nil, nil, handler)

			if test.expectError {
				require.Error(t, err, "expected error: "+test.description)
				assert.Equal(t, status.Error(codes.Unauthenticated, "request was not authenticated"), err)
				assert.Nil(t, retrievedAuth, "authentication should not be set in context")
			} else {
				require.NoError(t, err, "expected no error: "+test.description)
				assert.Equal(t, storedAuth, retrievedAuth, "expected authentication to be set in context")
			}
		})
	}
}

// TestRegression_NoServerLevelAuthenticationBypass tests that there is no mechanism
// to skip authentication for specific server instances.
//
// Issue: Certain internal servers (such as those handling delegated authentication flows)
// need to operate without authentication checks. There is currently no mechanism to
// configure the middleware to skip authentication for specific server instances, forcing
// all registered servers through the same authentication path regardless of their role.
func TestRegression_NoServerLevelAuthenticationBypass(t *testing.T) {
	authenticator := memory.NewStore()

	// Create a valid client token
	clientToken, _, err := authenticator.CreateAuthentication(
		context.TODO(),
		&auth.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	logger := zaptest.NewLogger(t)
	interceptor := auth.UnaryInterceptor(logger, authenticator)

	tests := []struct {
		name                    string
		setupMD                 func() metadata.MD
		methodName              string
		expectError             bool
		description             string
	}{
		{
			name: "authentication required service - with valid token",
			setupMD: func() metadata.MD {
				return metadata.MD{
					"Authorization": []string{"Bearer " + clientToken},
				}
			},
			methodName:  "/flipt.auth.AuthenticationService/GetAuthenticationSelf",
			expectError: false,
			description: "AuthenticationService requires authentication",
		},
		{
			name: "authentication required service - without token",
			setupMD: func() metadata.MD {
				return metadata.MD{}
			},
			methodName:  "/flipt.auth.AuthenticationService/GetAuthenticationSelf",
			expectError: true,
			description: "AuthenticationService requires authentication - no bypass possible",
		},
		{
			name: "internal delegated auth service - without token (should ideally be skipped)",
			setupMD: func() metadata.MD {
				return metadata.MD{}
			},
			methodName:  "/flipt.auth.DelegatedAuthService/Authenticate",
			expectError: true,
			description: "Internal services (if they existed) cannot skip authentication - no mechanism available",
		},
		{
			name: "flipt main service - without token",
			setupMD: func() metadata.MD {
				return metadata.MD{}
			},
			methodName:  "/flipt.Flipt/Evaluate",
			expectError: true,
			description: "Main Flipt service cannot skip authentication - all requests require auth",
		},
	}

	for _, test := range tests {
		test := test
		t.Run(test.name, func(t *testing.T) {
			ctx := metadata.NewIncomingContext(context.Background(), test.setupMD())

			var handlerCalled bool
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				handlerCalled = true
				return nil, nil
			}

			info := &grpc.UnaryServerInfo{
				Server:     nil,
				FullMethod: test.methodName,
			}

			_, err := interceptor(ctx, nil, info, handler)

			if test.expectError {
				require.Error(t, err, "expected error: "+test.description)
				// Handler should not be called when authentication fails
				assert.False(t, handlerCalled, "handler should not be called when authentication fails")
			} else {
				require.NoError(t, err, "expected no error: "+test.description)
				assert.True(t, handlerCalled, "handler should be called when authentication succeeds")
			}
		})
	}
}

// TestRegression_AuthenticationMiddlewareCannotBeSkipped tests that the authentication
// middleware applies uniformly to all services with no mechanism to skip it.
//
// This test specifically verifies that the middleware doesn't support:
// - Service-level authentication bypass configuration
// - Method-level authentication bypass configuration
// - Header-based authentication bypass
func TestRegression_AuthenticationMiddlewareCannotBeSkipped(t *testing.T) {
	authenticator := memory.NewStore()
	logger := zaptest.NewLogger(t)
	interceptor := auth.UnaryInterceptor(logger, authenticator)

	// Test that there's no configuration option or mechanism to skip auth
	tests := []struct {
		name            string
		setupMD         func() metadata.MD
		methodName      string
		expectError     bool
		description     string
	}{
		{
			name: "no auth header - authentication service",
			setupMD: func() metadata.MD {
				return metadata.MD{}
			},
			methodName:  "/flipt.auth.AuthenticationService/ListAuthentications",
			expectError: true,
			description: "Admin authentication endpoints require authentication - cannot be bypassed",
		},
		{
			name: "no auth header - token creation service",
			setupMD: func() metadata.MD {
				return metadata.MD{}
			},
			methodName:  "/flipt.auth.AuthenticationMethodTokenService/CreateToken",
			expectError: true,
			description: "Token creation endpoint requires authentication - cannot be bypassed",
		},
		{
			name: "no auth header - main API",
			setupMD: func() metadata.MD {
				return metadata.MD{}
			},
			methodName:  "/flipt.Flipt/ListFlags",
			expectError: true,
			description: "All Flipt API endpoints require authentication - cannot be bypassed",
		},
		{
			name: "special bypass header (hypothetical) - should still fail",
			setupMD: func() metadata.MD {
				return metadata.MD{
					"x-bypass-authentication": []string{"true"},
				}
			},
			methodName:  "/flipt.Flipt/ListFlags",
			expectError: true,
			description: "No special headers can bypass authentication",
		},
	}

	for _, test := range tests {
		test := test
		t.Run(test.name, func(t *testing.T) {
			ctx := metadata.NewIncomingContext(context.Background(), test.setupMD())

			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				return nil, nil
			}

			info := &grpc.UnaryServerInfo{
				Server:     nil,
				FullMethod: test.methodName,
			}

			_, err := interceptor(ctx, nil, info, handler)

			if test.expectError {
				require.Error(t, err, test.description)
				require.Equal(t, status.Error(codes.Unauthenticated, "request was not authenticated"), err)
			} else {
				require.NoError(t, err, test.description)
			}
		})
	}
}

// TestRegression_ExpiredTokensAreRejected is a baseline test to ensure
// that expired tokens are properly rejected (this should work correctly).
func TestRegression_ExpiredTokensAreRejected(t *testing.T) {
	authenticator := memory.NewStore()

	// Create an expired token
	expiredToken, _, err := authenticator.CreateAuthentication(
		context.TODO(),
		&auth.CreateAuthenticationRequest{
			Method:    authrpc.Method_METHOD_TOKEN,
			ExpiresAt: timestamppb.New(time.Now().UTC().Add(-time.Hour)),
		},
	)
	require.NoError(t, err)

	logger := zaptest.NewLogger(t)
	interceptor := auth.UnaryInterceptor(logger, authenticator)

	ctx := metadata.NewIncomingContext(
		context.Background(),
		metadata.MD{
			"Authorization": []string{"Bearer " + expiredToken},
		},
	)

	handler := func(ctx context.Context, req interface{}) (interface{}, error) {
		return nil, nil
	}

	_, err = interceptor(ctx, nil, nil, handler)

	require.Error(t, err)
	require.Equal(t, status.Error(codes.Unauthenticated, "request was not authenticated"), err)
}

// TestRegression_TokenValidationBehavior documents the expected token validation behavior
func TestRegression_TokenValidationBehavior(t *testing.T) {
	authenticator := memory.NewStore()

	// Create a valid token
	validToken, validAuth, err := authenticator.CreateAuthentication(
		context.TODO(),
		&auth.CreateAuthenticationRequest{
			Method:    authrpc.Method_METHOD_TOKEN,
			ExpiresAt: timestamppb.New(time.Now().UTC().Add(time.Hour)),
		},
	)
	require.NoError(t, err)

	logger := zaptest.NewLogger(t)
	interceptor := auth.UnaryInterceptor(logger, authenticator)

	tests := []struct {
		name              string
		token             string
		expectSuccess     bool
		expectedAuthID    string
		description       string
	}{
		{
			name:           "valid token with Bearer prefix",
			token:          "Bearer " + validToken,
			expectSuccess:  true,
			expectedAuthID: validAuth.Id,
			description:    "Valid tokens should be accepted",
		},
		{
			name:          "token without Bearer prefix",
			token:         validToken,
			expectSuccess: false,
			description:   "Token must have Bearer prefix",
		},
		{
			name:          "empty Bearer prefix",
			token:         "Bearer ",
			expectSuccess: false,
			description:   "Empty token after Bearer is invalid",
		},
		{
			name:          "wrong prefix",
			token:         "Token " + validToken,
			expectSuccess: false,
			description:   "Must use Bearer prefix, not Token",
		},
	}

	for _, test := range tests {
		test := test
		t.Run(test.name, func(t *testing.T) {
			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{
					"Authorization": []string{test.token},
				},
			)

			var retrievedAuth *authrpc.Authentication
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				retrievedAuth = auth.GetAuthenticationFrom(ctx)
				return nil, nil
			}

			_, err := interceptor(ctx, nil, nil, handler)

			if test.expectSuccess {
				require.NoError(t, err, test.description)
				require.NotNil(t, retrievedAuth)
				assert.Equal(t, test.expectedAuthID, retrievedAuth.Id)
			} else {
				require.Error(t, err, test.description)
				assert.Nil(t, retrievedAuth)
			}
		})
	}
}

